import { useNavigate } from "react-router-dom";
import ProjectCard from "./projectcard.js";
import Button from "./button.js";

function AboutMe() {
  const navigate = useNavigate();

  return (
    <div className="h2-homepage">
      Therese Wong is a multidisciplinary designer specialising in UX Research,
      Consulting, and Accessible Design
      <Button
        text="About Me"
        onClick={() => navigate("/about")} // This triggers the navigation
      />
    </div>
  );
}

export default AboutMe;
